using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ── FormatPhoneNumber ────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
        StringAssert.StartsWith(result, "(123)");
        StringAssert.EndsWith(result, "7890");
        StringAssert.Contains(result, "456");
    }

    [TestMethod]
    public void FormatPhoneNumber_AreaCodeIsWrappedInParentheses()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_NullThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLengthThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber("12345"));
    }

    // ── BuildGreeting ────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ReturnsCorrectGreeting()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
        StringAssert.StartsWith(result, "Dear");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    public void BuildGreeting_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_NullNameThrowsException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceNameThrowsException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting("   "));
    }

    // ── GenerateSlug ─────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_AreReplacedWithHyphens()
    {
        var result = _formatter.GenerateSlug("C# is great!!!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingWhitespace_IsTrimmed()
    {
        var result = _formatter.GenerateSlug("  Some Title  ");

        StringAssert.StartsWith(result, "some");
        StringAssert.EndsWith(result, "title");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpecialChars_CollapsedToSingleHyphen()
    {
        var result = _formatter.GenerateSlug("one---two???three");

        Assert.AreEqual("one-two-three", result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceThrowsException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    // ── FormatCurrency ───────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
        Assert.AreEqual("$9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(1234.5m, "€");

        StringAssert.StartsWith(result, "€");
        StringAssert.EndsWith(result, ".50");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWith00()
    {
        var result = _formatter.FormatCurrency(42m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_FormattedCorrectly()
    {
        var result = _formatter.FormatCurrency(-15.75m);

        Assert.AreEqual("$-15.75", result);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsSymbolAndZero()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }
}

